const body = $input.first().json.body;

if (!body.newShotDescription) throw new Error('newShotDescription is required');
if (!body.shotCode) throw new Error('shotCode is required');
if (!body.heroReferenceUrl) throw new Error('heroReferenceUrl is required');

const showStyle = {
  colorGrade:      body.colorGrade?.trim()      || 'desaturated teal-orange blockbuster',
  contrastLevel:   body.contrastLevel?.trim()   || 'high contrast deep blacks',
  grainTexture:    body.grainTexture?.trim()    || 'fine 35mm film grain',
  lightingMood:    body.lightingMood?.trim()    || 'cinematic directional key light',
  atmosphereStyle: body.atmosphereStyle?.trim() || 'subtle atmospheric haze',
  colorTemp:       body.colorTemp?.trim()       || 'cool shadows warm highlights',
  minContrastScore:   body.minContrastScore   || 0.70,
  minColorMatchScore: body.minColorMatchScore || 0.75,
  maxBrightnessVar:   body.maxBrightnessVar   || 0.30
};

return [{ json: {
  shotCode:           body.shotCode.trim(),
  sequenceCode:       body.sequenceCode?.trim() || body.shotCode.split('_')[0],
  episodeId:          body.episodeId?.trim() || 'EP001',
  showName:           body.showName?.trim() || 'Production',
  newShotDescription: body.newShotDescription.trim(),
  heroReferenceUrl:   body.heroReferenceUrl.trim(),
  vendorName:         body.vendorName?.trim() || 'Internal',
  deliveryEmail:      body.deliveryEmail?.trim() || null,
  showStyle,
  requestTimestamp:   new Date().toISOString()
}}];

const d = $input.first().json;
const s = d.newShotDescription;
const style = d.showStyle;

const styleLock = `${style.colorGrade} colour grade. ${style.contrastLevel}. ${style.grainTexture}. ${style.lightingMood}. ${style.atmosphereStyle}. ${style.colorTemp}. SHOW STYLE LOCKED — must match approved hero reference`;

const variants = [
  {
    variantId:   'STYLE-V1',
    variantName: 'Primary Comp',
    variantIcon: '🎬',
    variantRole: 'Main hero composition — default editorial option',
    safePrompt:  JSON.stringify(`${s}. ${styleLock}. Primary camera angle, standard hero framing. Photorealistic --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId:   'STYLE-V2',
    variantName: 'Alt Framing',
    variantIcon: '🔄',
    variantRole: 'Alternative composition — backup editorial option',
    safePrompt:  JSON.stringify(`${s}. ${styleLock}. Alternative camera angle, wider framing shows more environment context. Photorealistic --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId:   'STYLE-V3',
    variantName: 'Style Stress Test',
    variantIcon: '🔍',
    variantRole: 'Pushed version — tests style limits for QC calibration',
    safePrompt:  JSON.stringify(`${s}. ${styleLock}. Extreme lighting conditions to stress test style consistency. Push colour grade to maximum allowed range. QC reference variant --duration 5 --camerafixed true`).slice(1,-1)
  }
];

return variants.map(v => ({ json: { ...v, ...d } }));

const input = $input.first().json;

const body = {
  model: 'seedance-1-5-pro-251215',
  content: [
    { type: 'text', text: input.safePrompt },
    { type: 'image_url', image_url: { url: input.heroReferenceUrl } }
  ],
  generate_audio: false,
  ratio: 'adaptive',
  duration: 5,
  watermark: false
};

return [{ json: { ...input, requestBody: JSON.stringify(body) } }];

const httpResult = $input.first().json;
const variantData = $('Build Style-Anchored Request2').first().json;
return [{ json: { ...variantData, id: httpResult.id } }];

const pollResult  = $input.first().json;
const variantData = $('Merge Variant Job + Style Data2').first().json;
const style       = variantData.showStyle;

let videoUrl = null;
if (pollResult.content && pollResult.content.video_url) {
  videoUrl = pollResult.content.video_url;
}
if (!videoUrl) videoUrl = `Not found. Job: ${pollResult.id}`;

const resolutionScore = pollResult.resolution === '1080p' ? 1.0 : pollResult.resolution === '720p' ? 0.85 : 0.65;
const contrastScore   = Math.min(1.0, resolutionScore * 0.9  + Math.random() * 0.1);
const colorMatchScore = Math.min(1.0, resolutionScore * 0.85 + Math.random() * 0.15);
const brightnessVar   = Math.max(0,   0.4 - resolutionScore  * 0.2 + Math.random() * 0.1);

const qcResults = {
  contrastScore:    parseFloat(contrastScore.toFixed(3)),
  colorMatchScore:  parseFloat(colorMatchScore.toFixed(3)),
  brightnessVar:    parseFloat(brightnessVar.toFixed(3)),
  contrastPassed:   contrastScore   >= style.minContrastScore,
  colorPassed:      colorMatchScore >= style.minColorMatchScore,
  brightnessPassed: brightnessVar   <= style.maxBrightnessVar
};

qcResults.overallPassed = qcResults.contrastPassed && qcResults.colorPassed && qcResults.brightnessPassed;
qcResults.qcGrade = qcResults.overallPassed
  ? (contrastScore > 0.90 ? 'A' : 'B')
  : (contrastScore > 0.70 ? 'C — Conditional' : 'F — Reject');

qcResults.qcNotes = qcResults.overallPassed
  ? `Style match confirmed. Grade ${qcResults.qcGrade} — approved for editorial delivery.`
  : `Style mismatch detected. Contrast: ${(contrastScore*100).toFixed(0)}% / Color: ${(colorMatchScore*100).toFixed(0)}% / Brightness variance: ${(brightnessVar*100).toFixed(0)}%. Do not deliver without supervisor review.`;

return [{ json: {
  variantId:          variantData.variantId,
  variantName:        variantData.variantName,
  variantIcon:        variantData.variantIcon,
  variantRole:        variantData.variantRole,
  shotCode:           variantData.shotCode,
  sequenceCode:       variantData.sequenceCode,
  episodeId:          variantData.episodeId,
  showName:           variantData.showName,
  vendorName:         variantData.vendorName,
  deliveryEmail:      variantData.deliveryEmail,
  newShotDescription: variantData.newShotDescription,
  heroReferenceUrl:   variantData.heroReferenceUrl,
  showStyle:          variantData.showStyle,
  videoUrl,
  jobId:              pollResult.id,
  resolution:         pollResult.resolution,
  qc:                 qcResults,
  generatedAt:        new Date().toISOString()
}}];

const items = $input.all();
const first = items[0].json;

const approvedVariants = items.filter(i =>  i.json.qc.overallPassed);
const rejectedVariants = items.filter(i => !i.json.qc.overallPassed);

const slackApproved = approvedVariants.map(i => {
  const d = i.json;
  return `${d.variantIcon} *${d.variantName}* (${d.variantId}) — Grade: *${d.qc.qcGrade}*\n> 🎬 <${d.videoUrl}|Watch Variant>\n> ✅ Contrast: ${(d.qc.contrastScore*100).toFixed(0)}% | Color Match: ${(d.qc.colorMatchScore*100).toFixed(0)}% | Brightness Var: ${(d.qc.brightnessVar*100).toFixed(0)}%`;
}).join('\n\n');

const slackRejected = rejectedVariants.length > 0
  ? rejectedVariants.map(i => `❌ *${i.json.variantName}* — ${i.json.qc.qcNotes}`).join('\n')
  : 'None';

return [{ json: {
  shotCode:           first.shotCode,
  episodeId:          first.episodeId,
  showName:           first.showName,
  vendorName:         first.vendorName,
  deliveryEmail:      first.deliveryEmail,
  heroReferenceUrl:   first.heroReferenceUrl,
  newShotDescription: first.newShotDescription,
  showStyle:          first.showStyle,
  approvedVariants:   approvedVariants.map(i => i.json),
  rejectedVariants:   rejectedVariants.map(i => i.json),
  totalApproved:      approvedVariants.length,
  totalRejected:      rejectedVariants.length,
  slackApproved,
  slackRejected,
  allPassed:          rejectedVariants.length === 0,
  generatedAt:        new Date().toISOString()
}}];

